```python
def count_words(filename):
    with open(filename) as f:
        text = f.read()

    word_counts = {}

    for line in text.split('\n'):
        for word in line.split():
            word = word.lower()  # Convert the word to lowercase

            if word not in word_counts:
                word_counts[word] = 1
            else:
                word_counts[word] += 1

    return word_counts
